function getAudioContext() {
  if (!audioContext) audioContext = new (window.AudioContext || window.webkitAudioContext)();
  return audioContext;
}

function playTone(frequency, duration = 0.08, type = "sine", volume = 0.032) {
  if (!sfxEnabled) return;
  const ctx = getAudioContext();
  const oscillator = ctx.createOscillator();
  const gain = ctx.createGain();
  oscillator.type = type;
  oscillator.frequency.value = frequency;
  gain.gain.setValueAtTime(0, ctx.currentTime);
  gain.gain.linearRampToValueAtTime(volume, ctx.currentTime + 0.015);
  gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + duration);
  oscillator.connect(gain);
  gain.connect(ctx.destination);
  oscillator.start();
  oscillator.stop(ctx.currentTime + duration + 0.03);
}

function playSfx(kind) {
  if (kind === "correct") {
    playTone(659, 0.1, "triangle", 0.035);
    setTimeout(() => playTone(880, 0.12, "triangle", 0.032), 90);
  } else if (kind === "wrong") {
    playTone(294, 0.16, "sine", 0.026);
  } else if (kind === "complete") {
    [523, 659, 784].forEach((note, i) => setTimeout(() => playTone(note, 0.1, "triangle", 0.03), i * 80));
  } else {
    playTone(440, 0.045, "sine", 0.022);
  }
}

function startMusic() {
  if (!musicAudio) {
    const musicSource = window.SIMARS_MUSIC_DATA_URI || "./assets/music/calm-piano-background.mp3";
    musicAudio = new Audio(musicSource);
    musicAudio.volume = 0.3;
    musicAudio.preload = "auto";
    musicAudio.loop = false;
    musicAudio.addEventListener("ended", () => {
      musicEnabled = false;
      syncAudioButtons();
    });
  }
  musicAudio.play().catch(() => startGeneratedAmbientMusic());
}

function startGeneratedAmbientMusic() {
  const ctx = getAudioContext();
  const scale = [261.63, 293.66, 329.63, 392, 440, 493.88, 523.25, 587.33, 659.25];
  stopMusic();
  musicTimer = setInterval(() => {
    if (!musicEnabled) return;
    const root = scale[Math.floor(Math.random() * 5)];
    [root, root * 1.25, root * 1.5].forEach((frequency, i) => {
      const oscillator = ctx.createOscillator();
      const gain = ctx.createGain();
      oscillator.type = i === 0 ? "sine" : "triangle";
      oscillator.frequency.value = frequency;
      gain.gain.setValueAtTime(0, ctx.currentTime);
      gain.gain.linearRampToValueAtTime(0.008 / (i + 1), ctx.currentTime + 0.35 + i * 0.08);
      gain.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + 3.8 + Math.random() * 1.4);
      oscillator.connect(gain);
      gain.connect(ctx.destination);
      oscillator.start(ctx.currentTime + i * 0.06);
      oscillator.stop(ctx.currentTime + 5.3);
    });
  }, 4200);
}

function stopMusic() {
  if (musicAudio) {
    musicAudio.pause();
    musicAudio.currentTime = 0;
  }
  if (musicTimer) clearInterval(musicTimer);
  musicTimer = null;
}

function syncAudioButtons() {
  [musicToggle, lessonMusicToggle].forEach((button) => {
    if (!button) return;
    button.setAttribute("aria-pressed", String(musicEnabled));
    button.textContent = musicEnabled ? tr("musicOn") : tr("musicOff");
  });
  [sfxToggle, lessonSfxToggle].forEach((button) => {
    if (!button) return;
    button.setAttribute("aria-pressed", String(sfxEnabled));
    button.textContent = sfxEnabled ? tr("sfxOn") : tr("sfxOff");
  });
}

function toggleMusic() {
  musicEnabled = !musicEnabled;
  if (musicEnabled) startMusic();
  else stopMusic();
  syncAudioButtons();
  playSfx("click");
}

function toggleSfx() {
  sfxEnabled = !sfxEnabled;
  syncAudioButtons();
  if (sfxEnabled) playSfx("click");
}

function openLesson(lessonId) {
  currentLessonId = lessonId;
  currentStepIndex = 0;
  resetLessonWork();
  homeView.hidden = true;
  lessonView.hidden = false;
  renderLesson();
  focusLessonTop();
}

function closeLesson() {
  lessonView.hidden = true;
  homeView.hidden = false;
}

function focusLessonTop() {
  requestAnimationFrame(() => {
    lessonView.scrollIntoView({ block: "start", behavior: "smooth" });
  });
}

function renderLesson() {
  const lesson = localLesson();
  const stepData = lesson.steps[currentStepIndex];
  lessonNumber.textContent = languageMode === "zh" ? `第${currentLessonId}课` : `Lesson ${currentLessonId}`;
  lessonTitle.textContent = lesson.title;
  lessonKicker.textContent = lesson.kicker;
  stepTitle.textContent = stepData.title;
  stepCounter.textContent = `${currentStepIndex + 1} / ${lesson.steps.length}`;
  progressFill.style.width = `${((currentStepIndex + 1) / lesson.steps.length) * 100}%`;
  lectureTitle.textContent = currentStepIndex === 0 ? tr("notesTitle") : stepData.label;
  lectureBody.textContent = buildLectureText(lesson, stepData);
  stepNav.innerHTML = lesson.steps.map((item, index) => `
    <button class="step-button ${index === currentStepIndex ? "active" : ""}" data-step="${index}">
      <span>${index + 1}</span>${item.label}
    </button>
  `).join("");
  stepPanel.innerHTML = renderStep(stepData, lesson);
  bindStepInteractions();
}

function buildLectureText(lesson, stepData) {
  const zh = languageMode === "zh";
  const lessonOneHelp = {
    cover: zh ? "讲法：先让孩子猜未来十年会出现什么新变化，再把目标说出来：不是害怕AI，而是提前练能力。" : "Teaching: ask the child to guess changes in the next ten years, then explain that the goal is ability practice, not fear.",
    story: zh ? "讲法：故事要讲出未来职业背后的价值：帮助谁、解决什么问题、需要什么能力。" : "Teaching: focus on the value behind future jobs: who they help, what problem they solve, and what abilities they need.",
    rules: zh ? "讲法：三角形不用背，必须马上联系生活例子。让孩子说一个学校或家庭里的真实问题。" : "Teaching: connect the triangle to real daily examples instead of memorizing it.",
    puzzle: zh ? "讲法：让孩子自己点选线索。选完以后读完整观察，并说这和自己的生活有什么关系。" : "Teaching: let the child choose clues, read the observation, and connect it to their own life.",
    upgrade: zh ? "讲法：这是技能雷达。让孩子选择优先练的能力，并说为什么这个能力未来重要。" : "Teaching: this is an ability radar. Ask why each chosen ability matters.",
    repair: zh ? "讲法：把“替代焦虑”转成“能力判断”。重点是哪些人类能力让我们能和AI合作。" : "Teaching: turn replacement anxiety into ability judgment. Focus on human abilities for working with AI.",
    design: zh ? "讲法：这是输出页。请家长用问题帮助孩子想清楚，不要替孩子设计人生。" : "Teaching: this is the output page. Use questions; do not design the child's life for them.",
    duo: zh ? "讲法：适合两个孩子一起上。让他们互相采访，而不是比谁答案更快。" : "Teaching: good for two children. Let them interview each other instead of racing for answers.",
    summary: zh ? "讲法：不要只问“懂了吗”。让孩子说出一个变化、一个能力、一个本周行动。" : "Teaching: ask for one change, one ability, and one weekly action."
  };
  const lessonFiveHelp = {
    cover: zh ? "讲法：先让孩子看画面并猜今天学什么，再把目标说出来：不是学画画软件，而是学会说清楚。" : "Teaching: let the child look and guess first, then explain that the goal is clear expression.",
    story: zh ? "讲法：故事要讲出第一次为什么失败、爸爸怎么追问、第二次为什么更接近想象。" : "Teaching: show why the first prompt failed, how the parent asked, and why the second became clearer.",
    rules: zh ? "讲法：四件套不用背，必须马上用。每讲一个词，请孩子立刻举自己的例子。" : "Teaching: do not memorize. Use each part immediately with the child's examples.",
    puzzle: zh ? "讲法：让孩子自己点选组合。选完以后读完整句，并补一句“我还想加……”" : "Teaching: let the child choose and read the full prompt, then add one more detail.",
    upgrade: zh ? "讲法：先让孩子说原句哪里模糊，再点按钮一点点升级。重点是孩子能解释升级原因。" : "Teaching: ask why the original is vague, then upgrade it step by step.",
    repair: zh ? "讲法：告诉孩子，AI画错不是失败，而是进入第二轮表达。修改时说清楚改变和保留。" : "Teaching: AI mistakes begin the second round of expression. Say what to change and what to keep.",
    design: zh ? "讲法：这是输出页。请家长做记录员，不要抢孩子的答案。" : "Teaching: this is the output page. The parent records but does not take over.",
    duo: zh ? "讲法：适合两个孩子一起上。让他们互相提一个让画面更清楚的问题。" : "Teaching: good for two children. Let them ask each other one clarity question.",
    summary: zh ? "讲法：不要只问“懂了吗”。让孩子完整说出过程、方法、下次怎么用。" : "Teaching: do not only ask 'do you understand'. Ask the child to explain the process, method, and next use."
  };
  const lessonFourHelp = {
    cover: zh ? "讲法：先用“帮我弄一下”这种模糊表达开场，让孩子发现AI也需要清楚说明。" : "Teaching: start with a vague request so the child sees why AI needs clear instructions.",
    story: zh ? "讲法：故事要讲出AI不是坏，而是任务没说清楚。孩子负责目标、真实和判断。" : "Teaching: show that AI is not the problem; the task was unclear. The child owns goal, truth, and judgment.",
    rules: zh ? "讲法：四件套不要背概念。每讲一个词，马上换成孩子熟悉的学习场景。" : "Teaching: do not memorize the four parts. Connect each one to a familiar learning task.",
    puzzle: zh ? "讲法：让孩子自己点选并读出完整提示词，再检查有没有角色、任务、背景、约束。" : "Teaching: let the child choose, read the prompt aloud, and check the four parts.",
    upgrade: zh ? "讲法：不要直接给标准答案。让孩子说每增加一句，到底减少了哪种误解。" : "Teaching: ask what misunderstanding each new phrase prevents.",
    repair: zh ? "讲法：把AI答偏当作训练机会。让孩子说清楚要变短、变像自己、保留真实、不编故事。" : "Teaching: treat a poor answer as practice. Ask the child to name what should change and what must stay.",
    design: zh ? "讲法：这是输出页。家长做打字员，孩子做任务设计师。" : "Teaching: this is the output page. The parent types; the child designs the task.",
    duo: zh ? "讲法：适合两个孩子互相检查四件套。重点不是谁快，而是谁能问得清楚。" : "Teaching: let two children check each other's four parts. Clarity matters more than speed.",
    summary: zh ? "讲法：请孩子选择一个真实任务，准备复制到豆包或 DeepSeek 里测试，并学会追问。" : "Teaching: ask the child to choose one real task to test in Doubao or DeepSeek and practice follow-up."
  };
  const helpMap = currentLessonId === 1 ? lessonOneHelp : currentLessonId === 4 ? lessonFourHelp : lessonFiveHelp;
  const typeHelp = helpMap[stepData.type];
  return [currentStepIndex === 0 ? lesson.prep : stepData.guide, typeHelp].filter(Boolean).join("\n\n");
}

function tipsMarkup(lesson) {
  return `<div class="page-tips"><strong>${tr("parentTips")}</strong><span>${lesson.tips[currentStepIndex % lesson.tips.length]}</span></div>`;
}

function visualMarkup(stepData) {
  const coverImage = lessonCoverImages[currentLessonId];
  const stepImage = lessonStepImages[currentLessonId]?.[stepData.type];
  if (stepData.type === "cover" && coverImage) {
    return `<div class="visual-card cover-image-card"><img src="${coverImage}" alt="${lessonDetails[currentLessonId][languageMode].title}"></div>`;
  }
  if (stepImage) {
    return `<div class="visual-card step-image-card"><img src="${stepImage}" alt="${stepData.title}"></div>`;
  }
  return `<div class="visual-card">${visualScene(stepData.type)}</div>`;
}

function renderStep(stepData, lesson) {
  const visual = visualMarkup(stepData);
  const tips = tipsMarkup(lesson);
  if (["cover", "story", "rules"].includes(stepData.type)) {
    return `
      <div class="panel-grid">
        <div class="content-card child-card">
          <span class="time-tag">${stepData.minutes}</span>
          <div class="big-line">${stepData.body}</div>
          ${stepData.quote ? `<div class="quote-box">${stepData.quote}</div>` : ""}
          ${stepData.bullets?.length ? `<ul class="rule-list">${stepData.bullets.map((item) => `<li>${item}</li>`).join("")}</ul>` : ""}
        </div>
        ${visual}
      </div>
      ${tips}
    `;
  }
  if (stepData.type === "puzzle") {
    return `
      <div class="game-grid">
        <div class="game-card">
          <span class="time-tag">${stepData.minutes}</span>
          <p>${stepData.prompt}</p>
          <div class="prompt-groups">
            ${stepData.groups.map((group, index) => `
              <section>
                <strong>${group.name}</strong>
                <div class="chip-grid" data-puzzle-group="${index}">
                  ${group.options.map((option) => `<button class="chip" data-piece="${option}">${option}</button>`).join("")}
                </div>
              </section>
            `).join("")}
          </div>
        </div>
        <div class="content-card prompt-card">
          ${visualScene("puzzle")}
          <h3>${languageMode === "zh" ? "生成的清楚指令" : "Clear Prompt"}</h3>
          <div class="prompt-output" data-puzzle-output>${lessonWork.puzzle || (languageMode === "zh" ? "每组点一个，完整指令会出现在这里。" : "Choose one from each group to build the prompt.")}</div>
          ${outputActionsMarkup("puzzle")}
        </div>
      </div>
      ${tips}
    `;
  }
  if (stepData.type === "upgrade") {
    return `
      <div class="game-grid">
        <div class="game-card">
          <span class="time-tag">${stepData.minutes}</span>
          <p class="big-line">${stepData.prompt}</p>
          <div class="chip-grid" data-upgrade>
            ${stepData.choices.map((item) => `<button class="chip" data-piece="${item}">${item}</button>`).join("")}
          </div>
        </div>
        <div class="content-card prompt-card">
          ${visualScene("upgrade")}
          <h3>${languageMode === "zh" ? "升级后" : "Upgraded"}</h3>
          <div class="prompt-output" data-upgrade-output>${lessonWork.upgrade || (languageMode === "zh" ? "点击补充信息，把模糊句变清楚。" : "Tap details to make it clearer.")}</div>
          ${outputActionsMarkup("upgrade")}
        </div>
      </div>
      ${tips}
    `;
  }
  if (stepData.type === "repair") {
    return `
      <div class="game-grid">
        <div class="game-card">
          <span class="time-tag">${stepData.minutes}</span>
          <div class="ai-mistake">
            <div>${visualScene("repair")}</div>
            <p>${stepData.problem}</p>
          </div>
          <div class="chip-grid" data-repair>
            ${stepData.options.map((item) => `<button class="chip" data-piece="${item}">${item}</button>`).join("")}
          </div>
        </div>
        <div class="content-card prompt-card">
          ${visual}
          <h3>${languageMode === "zh" ? "修改指令" : "Revision Prompt"}</h3>
          <div class="prompt-output" data-repair-output>${lessonWork.repair || stepData.target}</div>
          ${outputActionsMarkup("repair")}
        </div>
      </div>
      ${tips}
    `;
  }
  if (stepData.type === "design") {
    return `
      <div class="game-grid">
        <div class="game-card">
          <span class="time-tag">${stepData.minutes}</span>
          <div class="design-form" data-design-form>
            ${stepData.fields.map((field) => `
              <label>
                <span>${field}</span>
                <input type="text" placeholder="${stepData.placeholder}" data-design-field="${field}">
              </label>
            `).join("")}
          </div>
        </div>
        <div class="content-card prompt-card">
          ${visual}
          <h3>${languageMode === "zh" ? "我的完整指令" : "My Full Prompt"}</h3>
          <div class="prompt-output" data-design-output>${lessonWork.design || (languageMode === "zh" ? "填完左边四格，这里会自动组成一句话。" : "Fill the four fields to build one sentence.")}</div>
          ${outputActionsMarkup("design")}
        </div>
      </div>
      ${tips}
    `;
  }
  if (stepData.type === "duo") {
    return `
      <div class="duo-grid">
        ${stepData.kids.map((kid) => `
          <div class="teacher-card kid-card">
            ${visualScene("duo")}
            <span class="time-tag">${kid.name}</span>
            <h3>${kid.mission}</h3>
            <ul class="rule-list">${kid.starter.map((item) => `<li contenteditable="true">${item}</li>`).join("")}</ul>
          </div>
        `).join("")}
      </div>
      ${tips}
    `;
  }
  return `
    <div class="summary-grid">
      <div class="teacher-card">
        <span class="time-tag">${stepData.minutes}</span>
        <p class="big-line">${stepData.chant}</p>
        ${visual}
      </div>
      <div class="teacher-card">
        <h3>${languageMode === "zh" ? "完整复盘" : "Full Review"}</h3>
        <div class="teacher-grid review-grid">${stepData.recap.map((item, index) => `<div><strong>${index + 1}</strong><span>${item}</span></div>`).join("")}</div>
      </div>
      ${workSummaryMarkup()}
    </div>
    ${tips}
  `;
}

function outputActionsMarkup(kind) {
  return `
    <div class="prompt-actions">
      <button class="secondary-action compact-action" data-copy-output="${kind}">${languageMode === "zh" ? "复制指令" : "Copy"}</button>
      <span data-work-status="${kind}">${lessonWork[kind] ? (languageMode === "zh" ? "已放入作品卡" : "Saved") : (languageMode === "zh" ? "完成后自动放入作品卡" : "Saved after completion")}</span>
    </div>
  `;
}

function workSummaryMarkup() {
  const labels = languageMode === "zh"
    ? (currentLessonId === 1
      ? { puzzle: "未来观察", upgrade: "技能选择", repair: "抗替代判断", design: "我的未来能力卡" }
      : currentLessonId === 4
        ? { puzzle: "黄金提示词", upgrade: "升级请求", repair: "修正要求", design: "我的提问作品卡" }
      : { puzzle: "拼图指令", upgrade: "升级指令", repair: "修正指令", design: "我的设计卡" })
    : (currentLessonId === 1
      ? { puzzle: "Future observation", upgrade: "Ability choices", repair: "Replacement judgment", design: "My future ability card" }
      : currentLessonId === 4
        ? { puzzle: "Golden prompt", upgrade: "Upgraded request", repair: "Revision request", design: "My prompt card" }
      : { puzzle: "Puzzle prompt", upgrade: "Upgraded prompt", repair: "Revision prompt", design: "My design card" });
  const empty = languageMode === "zh" ? "这一项还没有完成，可以回到对应页面补上。" : "Not completed yet. Go back to this step to finish it.";
  const handoffSteps = languageMode === "zh"
    ? (currentLessonId === 1
      ? ["复制孩子最后的未来能力卡", "打开豆包或 DeepSeek App 的对话入口", "让孩子亲手粘贴，并追问：请帮我设计一个本周能完成的小任务", "一起判断AI建议：是否安全？是否可执行？是否真的适合我？"]
      : currentLessonId === 4
        ? ["复制孩子最后的黄金提示词", "打开豆包或 DeepSeek App 的对话入口", "让孩子亲手粘贴并发送", "一起观察AI回答：有没有听懂任务？哪里需要继续追问？"]
      : ["复制孩子最后的设计卡提示词", "打开豆包或 DeepSeek App 的对话/绘图入口", "让孩子亲手粘贴并发送", "一起观察结果：哪里像？哪里不像？下一句怎么改？"])
    : (currentLessonId === 1
      ? ["Copy the child's future ability card", "Open Doubao or DeepSeek chat", "Let the child paste it and ask for one weekly task", "Review together: is it safe, doable, and suitable?"]
      : currentLessonId === 4
        ? ["Copy the child's golden prompt", "Open Doubao or DeepSeek chat", "Let the child paste and send it", "Review together: did AI understand the task, and what follow-up is needed?"]
      : ["Copy the child's final design-card prompt", "Open Doubao or DeepSeek and choose chat/image creation", "Let the child paste and send it", "Review together: what matches, what misses, and how should we revise?"]);
  const handoffTitle = languageMode === "zh"
    ? (currentLessonId === 1 ? "家长带孩子去 App 里优化任务" : currentLessonId === 4 ? "家长带孩子去 App 里实测提问" : "家长带孩子去 App 里生成")
    : (currentLessonId === 1 ? "Parent-guided task refinement" : currentLessonId === 4 ? "Parent-guided prompt test" : "Parent-guided app handoff");
  const workCardIntro = languageMode === "zh"
    ? (currentLessonId === 1 ? "下一步不是让AI替孩子决定未来，而是让孩子学会用AI帮助自己制定一个小行动。" : currentLessonId === 4 ? "下一步不是让AI替孩子完成作业，而是让孩子看到：问题说清楚，AI才更容易帮到自己。" : "下一步不是让AI替孩子想，而是让孩子看到自己的表达真的能变成画面。")
    : (currentLessonId === 1 ? "Next, use AI to help the child turn one ability into a small action, not to decide their future." : currentLessonId === 4 ? "Next, help the child see that AI works better when the task is clear." : "Next, let the child see how their own words can become an image.");
  return `
    <div class="teacher-card work-card">
      <div class="work-card-head">
        <span class="time-tag">${languageMode === "zh" ? "作品卡" : "Work Card"}</span>
        <h3>${languageMode === "zh" ? "孩子今天完成了什么" : "What the child made today"}</h3>
        <p>${workCardIntro}</p>
      </div>
      <div class="app-handoff">
        <strong>${handoffTitle}</strong>
        <ol>
          ${handoffSteps.map((item) => `<li>${item}</li>`).join("")}
        </ol>
        <button class="secondary-action compact-action" data-copy-work="design">${languageMode === "zh" ? "复制最后作品卡" : "Copy final card"}</button>
      </div>
      <div class="work-list">
        ${Object.keys(labels).map((key) => `
          <section>
            <strong>${labels[key]}</strong>
            <p>${lessonWork[key] || empty}</p>
          </section>
        `).join("")}
      </div>
    </div>
  `;
}

function joinPrompt(parts) {
  if (!parts.length) return languageMode === "zh" ? "点击补充信息，把指令变清楚。" : "Tap details to make the prompt clearer.";
  if (currentLessonId === 1) {
    return languageMode === "zh"
      ? `我的未来观察：${parts.join("；")}。我会先选择一个小任务练习，让自己更会和AI合作。`
      : `My future observation: ${parts.join("; ")}. I will choose one small task to practice working with AI.`;
  }
  if (currentLessonId === 4) {
    return languageMode === "zh"
      ? `我的黄金提示词：${parts.join("；")}。请按这些要求回答，先解释思路，再给我一个适合小学生的结果。`
      : `My golden prompt: ${parts.join("; ")}. Please follow these requirements, explain your thinking first, then give a child-friendly result.`;
  }
  return languageMode === "zh"
    ? `请帮我画：${parts.join("，")}。画面适合小学生，明亮、友好、有轻微未来感。`
    : `Please draw: ${parts.join(", ")}. Make it bright, friendly, lightly futuristic, and suitable for children.`;
}

function recordWork(kind, value) {
  const clean = value.trim();
  lessonWork[kind] = clean;
  const status = document.querySelector(`[data-work-status="${kind}"]`);
  if (status) status.textContent = clean ? (languageMode === "zh" ? "已放入作品卡" : "Saved") : (languageMode === "zh" ? "完成后自动放入作品卡" : "Saved after completion");
}

function outputSelector(kind) {
  return `[data-${kind}-output]`;
}

function bindStepInteractions() {
  document.querySelectorAll("[data-puzzle-group] .chip").forEach((button) => {
    button.addEventListener("click", () => {
      const group = button.closest("[data-puzzle-group]");
      group.querySelectorAll(".chip").forEach((item) => item.classList.remove("selected"));
      button.classList.add("selected");
      const pieces = Array.from(document.querySelectorAll("[data-puzzle-group] .chip.selected")).map((item) => item.dataset.piece);
      document.querySelector("[data-puzzle-output]").textContent = joinPrompt(pieces);
      recordWork("puzzle", pieces.length >= 4 ? joinPrompt(pieces) : "");
      playSfx(pieces.length >= 4 ? "complete" : "click");
    });
  });
  document.querySelectorAll("[data-upgrade] .chip").forEach((button) => {
    button.addEventListener("click", () => {
      button.classList.toggle("selected");
      const pieces = Array.from(document.querySelectorAll("[data-upgrade] .chip.selected")).map((item) => item.dataset.piece);
      document.querySelector("[data-upgrade-output]").textContent = joinPrompt(pieces);
      recordWork("upgrade", pieces.length >= 4 ? joinPrompt(pieces) : "");
      playSfx(pieces.length >= 4 ? "complete" : "click");
    });
  });
  document.querySelectorAll("[data-repair] .chip").forEach((button) => {
    button.addEventListener("click", () => {
      button.classList.toggle("selected");
      const pieces = Array.from(document.querySelectorAll("[data-repair] .chip.selected")).map((item) => item.dataset.piece);
      document.querySelector("[data-repair-output]").textContent = pieces.length ? joinPrompt(pieces) : localLesson().steps[currentStepIndex].target;
      recordWork("repair", pieces.length >= 4 ? joinPrompt(pieces) : "");
      playSfx(pieces.length >= 4 ? "complete" : "click");
    });
  });
  document.querySelectorAll("[data-design-field]").forEach((input) => {
    input.addEventListener("input", () => {
      const values = Array.from(document.querySelectorAll("[data-design-field]")).map((field) => field.value.trim()).filter(Boolean);
      document.querySelector("[data-design-output]").textContent = values.length ? joinPrompt(values) : (languageMode === "zh" ? "填完左边四格，这里会自动组成一句话。" : "Fill the four fields to build one sentence.");
      recordWork("design", values.length >= 4 ? joinPrompt(values) : "");
    });
  });
}

document.addEventListener("click", (event) => {
  const opener = event.target.closest("[data-open-lesson]");
  if (opener) {
    playSfx("click");
    openLesson(Number(opener.dataset.openLesson));
  }
  const stepButton = event.target.closest("[data-step]");
  if (stepButton) {
    playSfx("click");
    currentStepIndex = Number(stepButton.dataset.step);
    renderLesson();
    focusLessonTop();
  }
  const copyButton = event.target.closest("[data-copy-output]");
  if (copyButton) {
    const kind = copyButton.dataset.copyOutput;
    const output = document.querySelector(outputSelector(kind));
    const text = output?.textContent?.trim();
    if (!text) return;
    navigator.clipboard?.writeText(text);
    copyButton.textContent = languageMode === "zh" ? "已复制" : "Copied";
    playSfx("complete");
    setTimeout(() => {
      copyButton.textContent = languageMode === "zh" ? "复制指令" : "Copy";
    }, 1200);
  }
  const copyWorkButton = event.target.closest("[data-copy-work]");
  if (copyWorkButton) {
    const kind = copyWorkButton.dataset.copyWork;
    const text = lessonWork[kind] || "";
    if (!text) return;
    navigator.clipboard?.writeText(text);
    copyWorkButton.textContent = languageMode === "zh" ? "已复制，去App粘贴" : "Copied";
    playSfx("complete");
    setTimeout(() => {
      copyWorkButton.textContent = languageMode === "zh" ? "复制最后作品卡" : "Copy final card";
    }, 1400);
  }
});

backHome.addEventListener("click", () => {
  playSfx("click");
  closeLesson();
});
prevStep.addEventListener("click", () => {
  currentStepIndex = Math.max(0, currentStepIndex - 1);
  playSfx("click");
  renderLesson();
  focusLessonTop();
});
nextStep.addEventListener("click", () => {
  currentStepIndex = Math.min(localLesson().steps.length - 1, currentStepIndex + 1);
  playSfx("click");
  renderLesson();
  focusLessonTop();
});
scrollCatalog.addEventListener("click", () => {
  playSfx("click");
  document.querySelector("#catalog").scrollIntoView({ behavior: "smooth" });
});
languageSelect.addEventListener("change", () => {
  languageMode = languageSelect.value;
  playSfx("click");
  updateStaticLanguage();
});
[musicToggle, lessonMusicToggle].forEach((button) => button.addEventListener("click", toggleMusic));
[sfxToggle, lessonSfxToggle].forEach((button) => button.addEventListener("click", toggleSfx));
lectureToggle.addEventListener("click", () => {
  lectureCollapsed = !lectureCollapsed;
  lecturePanel.classList.toggle("collapsed", lectureCollapsed);
  lectureToggle.setAttribute("aria-pressed", String(!lectureCollapsed));
  lectureToggle.textContent = lectureCollapsed ? tr("expandNotes") : tr("collapseNotes");
  playSfx("click");
});
document.addEventListener("keydown", (event) => {
  if (lessonView.hidden) return;
  if (event.key === "ArrowRight") nextStep.click();
  if (event.key === "ArrowLeft") prevStep.click();
});

updateStaticLanguage();
